  function blankPlayer() {
    return { pos: "", no: "", family: "", given: "", half: false, yellow: false };
  }

  function makeBlankPlayers(count) {
    return Array.from({ length: count }, blankPlayer);
  }

  function normalizePlayer(player, fallback = blankPlayer()) {
    const source = player && typeof player === "object" ? player : {};
    return {
      pos: source.pos ?? fallback.pos ?? "",
      no: source.no ?? fallback.no ?? "",
      family: source.family ?? fallback.family ?? "",
      given: source.given ?? fallback.given ?? "",
      half: source.half === undefined ? Boolean(fallback.half) : Boolean(source.half),
      yellow: Boolean(source.yellow)
    };
  }

  function normalizePlayerList(input, fallback, count) {
    const list = makeBlankPlayers(count);
    const source = Array.isArray(input) ? input : fallback;
    (source || []).slice(0, count).forEach((player, index) => {
      list[index] = normalizePlayer(player, list[index]);
    });
    return list;
  }

  function scorerFullName(scorer) {
    if (!scorer) return "";
    if (scorer.name != null && !scorer.family && !scorer.given) return String(scorer.name);
    return `${scorer.family || ""}${scorer.given ? `　${scorer.given}` : ""}`.trim();
  }

  function normalizeScorer(scorer) {
    const source = scorer && typeof scorer === "object" ? scorer : {};
    const parsed = splitPlayerName(source.name != null ? source.name : scorerFullName(source));
    return {
      minute: source.minute != null ? String(source.minute) : "",
      family: source.family != null ? String(source.family) : parsed.family,
      given: source.given != null ? String(source.given) : parsed.given,
      half: source.half === undefined ? parsed.half : Boolean(source.half)
    };
  }

  function normalizeScorerList(input, fallback) {
    const source = Array.isArray(input) ? input : fallback;
    const list = makeBlankScorers();
    (source || []).slice(0, MAX_SCORERS).forEach((scorer, index) => {
      list[index] = normalizeScorer(scorer);
    });
    return list;
  }

  function normalizeRefereeList(input, fallback) {
    const source = Array.isArray(input) ? input : fallback;
    const list = makeBlankReferees();
    const normalized = [];
    (source || []).forEach((referee) => {
      const role = referee && referee.role != null ? String(referee.role) : "";
      const name = referee && referee.name != null ? String(referee.name) : "";
      pushReferee(normalized, role, name);
    });
    normalized.slice(0, MAX_REFEREES).forEach((referee, index) => {
      list[index] = referee;
    });
    return list;
  }

  function isOldDefaultHomeScorerOrder(scorers) {
    if (!Array.isArray(scorers) || scorers.length < 2) return false;
    return scorers[0].minute === "87"
      && scorerFullName(scorers[0]) === "若月　大和"
      && scorers[1].minute === "47"
      && scorerFullName(scorers[1]) === "シマブク　カズヨシ";
  }

  function isAllowedImageSource(value) {
    const text = String(value || "");
    return text.startsWith("data:")
      || /^icons\/[^"'<>]+\.(png|webp|jpg|jpeg|svg)(\?[^"'<>]*)?$/i.test(text)
      || /^\.\.\/data\/assets\/[^"'<>]+\.(png|webp|jpg|jpeg|svg)(\?[^"'<>]*)?$/i.test(text)
      || /^data\/assets\/[^"'<>]+\.(png|webp|jpg|jpeg|svg)(\?[^"'<>]*)?$/i.test(text);
  }

  function loadState() {
    try {
      const raw = localStorage.getItem(STORAGE_KEY);
      return raw ? normalizeState(JSON.parse(raw)) : clone(defaultState);
    } catch (error) {
      return clone(defaultState);
    }
  }

  function normalizeState(input) {
    const state = clone(defaultState);
    if (!input || typeof input !== "object") return state;

    if (input.colors) {
      state.colors.home = input.colors.home || state.colors.home;
      state.colors.away = input.colors.away || state.colors.away;
    }
    if (input.textColors) {
      state.textColors.homeClub = input.textColors.homeClub || state.textColors.homeClub;
      state.textColors.awayClub = input.textColors.awayClub || state.textColors.awayClub;
      state.textColors.homeNumber = input.textColors.homeNumber || state.textColors.homeNumber;
      state.textColors.awayNumber = input.textColors.awayNumber || state.textColors.awayNumber;
    }
    if (input.images) {
      state.images.league = isAllowedImageSource(input.images.league) ? input.images.league : "";
      state.images.bottom = isAllowedImageSource(input.images.bottom) ? input.images.bottom : "";
    }
    state.images.bottom = state.images.bottom || ((input.image && input.image.startsWith("data:")) ? input.image : "");
    state.image = state.images.bottom;

    ["home", "away"].forEach((side) => {
      if (!input[side]) return;
      state[side].club = input[side].club ?? state[side].club;
      if (Array.isArray(input[side].players)) {
        state[side].players = normalizePlayerList(input[side].players, state[side].players, 11);
      }
      if (Array.isArray(input[side].startingPlayers)) {
        state[side].startingPlayers = normalizePlayerList(input[side].startingPlayers, state[side].startingPlayers || state[side].players, 11);
      } else {
        state[side].startingPlayers = normalizePlayerList(state[side].startingPlayers || state[side].players, state[side].players, 11);
      }
      if (Array.isArray(input[side].reserves)) {
        state[side].reserves = normalizePlayerList(input[side].reserves, state[side].reserves, MAX_RESERVES);
      }
    });

    if (input.match) {
      Object.keys(state.match).forEach((key) => {
        state.match[key] = input.match[key] ?? state.match[key];
      });
      state.match.phase = input.match.phase === "kickoff" ? "kickoff" : "fulltime";
    }

    if (input.result) {
      state.result.homeScorers = normalizeScorerList(input.result.homeScorers, state.result.homeScorers);
      state.result.awayScorers = normalizeScorerList(input.result.awayScorers, state.result.awayScorers);
      if (isOldDefaultHomeScorerOrder(state.result.homeScorers)) {
        state.result.homeScorers = normalizeScorerList([
          state.result.homeScorers[1],
          state.result.homeScorers[0],
          ...state.result.homeScorers.slice(2)
        ], state.result.homeScorers);
      }
    }

    if (input.attendance) {
      state.attendance.title = input.attendance.title ?? state.attendance.title;
      state.attendance.count = input.attendance.count ?? state.attendance.count;
      state.attendance.message = input.attendance.message ?? state.attendance.message;
    }

    if (input.top) {
      state.top.year = input.top.year ?? state.top.year;
      state.top.kickoff = input.top.kickoff ?? state.top.kickoff;
      state.top.eventName = input.top.eventName ?? state.top.eventName;
      state.top.homeEnglish = input.top.homeEnglish ?? state.top.homeEnglish;
      state.top.awayEnglish = input.top.awayEnglish ?? state.top.awayEnglish;
    }

    if (Array.isArray(input.referees)) {
      state.referees = normalizeRefereeList(input.referees, state.referees);
    }

    if (input.announcements) {
      state.announcements.startingSide = input.announcements.startingSide === "home" ? "home" : "away";
      state.announcements.reserveSide = input.announcements.reserveSide === "home" ? "home" : "away";
    }

    return state;
  }

  function saveState(state, broadcast) {
    const next = normalizeState(state);
    localStorage.setItem(STORAGE_KEY, JSON.stringify(next));
    currentState = next;
    if (broadcast && channel) channel.postMessage(next);
  }

  function getPath(target, path) {
    return path.split(".").reduce((value, key) => (value == null ? "" : value[key]), target);
  }

  function setPath(target, path, value) {
    const parts = path.split(".");
    const last = parts.pop();
    const parent = parts.reduce((value, key) => value[key], target);
    parent[last] = value;
  }

  function toHalfWidthKana(value) {
    return Array.from(value || "").map((char) => kanaMap[char] || char).join("");
  }

  const wideKanaMap = Object.entries(kanaMap).reduce((acc, [wide, half]) => {
    acc[half] = wide;
    return acc;
  }, {});

  function halfKanaUnitToWide(unit) {
    const chars = Array.from(unit || "");
    let result = "";
    for (let index = 0; index < chars.length; index += 1) {
      const char = chars[index];
      const pair = chars[index + 1] && wideKanaMap[char + chars[index + 1]];
      if (pair) {
        result += pair;
        index += 1;
      } else {
        result += wideKanaMap[char] || char;
      }
    }
    return result;
  }

  function toWideKana(value) {
    return kanaUnits(value).map((unit) => wideKanaMap[unit] || halfKanaUnitToWide(unit)).join("");
  }

  const fullSmallKana = new Set(["ァ", "ィ", "ゥ", "ェ", "ォ", "ャ", "ュ", "ョ", "ッ"]);

  function visualKanaUnits(value) {
    return Array.from(toWideKana(value));
  }

  function compactUnitLength(units) {
    return (units || []).reduce((sum, unit) => sum + (fullSmallKana.has(unit) ? 0.62 : 1), 0);
  }

  function shouldUseCompactName(player) {
    if (!player || !player.half) return false;
    const familyCount = Array.from(String(player.family || "").replace(/\s+/g, "")).length;
    const givenCount = Array.from(String(player.given || "").replace(/\s+/g, "")).length;
    const total = familyCount + givenCount;
    if (givenCount > 0) return total >= 6;
    return total >= 7;
  }

  function kanaUnits(value) {
    const normalized = toHalfWidthKana(value);
    const units = [];
    Array.from(normalized).forEach((char) => {
      if ((marks.has(char) || halfSmallKana.has(char)) && units.length) {
        units[units.length - 1] += char;
      } else {
        units.push(char);
      }
    });
    return units;
  }

  function textUnits(value, compact) {
    if (!value) return [];
    if (compact) {
      return visualKanaUnits(value);
    }
    return Array.from(value);
  }

  function nameBlockWidth(count, total, longName, compact = false, visualLength = count) {
    if (!count) return 0;
    if (compact) {
      const base = Math.max(72, count * 32, visualLength * 42 + 12);
      if (total >= 10) return Math.min(220, base);
      if (total >= 8) return Math.min(210, base);
      return Math.min(205, base);
    }
    if (longName) {
      if (count === 1) return 54;
      if (count === 2) return total >= 8 ? 112 : 126;
      if (count === 3) return 176;
      if (count === 4) return 228;
      return Math.min(270, Math.max(228, count * 48));
    }
    if (count === 1) return total <= 4 ? 58 : 49;
    if (count === 2) {
      if (total === 5) return 108;
      return total <= 3 ? (longName ? 136 : 150) : (longName ? 118 : 126);
    }
    if (count === 3) return total <= 4 ? 212 : (total === 5 ? 190 : 196);
    return 214;
  }

  function balanceNameWidths(familyWidth, givenWidth, familyUnits, givenUnits, totalUnits, compact, longName) {
    if (!compact && !longName && familyUnits === 3 && givenUnits === 1 && totalUnits === 4) {
      return { familyWidth: Math.max(familyWidth, 212), givenWidth: Math.max(givenWidth, 58) };
    }
    if (!compact && !longName && familyUnits === 3 && givenUnits === 2 && totalUnits === 5) {
      return { familyWidth: Math.max(familyWidth, 190), givenWidth: Math.max(givenWidth, 108) };
    }
    if (!compact && !longName && familyUnits === 2 && givenUnits === 3 && totalUnits === 5) {
      return { familyWidth: Math.max(familyWidth, 108), givenWidth: Math.max(givenWidth, 190) };
    }
    return { familyWidth, givenWidth };
  }

  function shouldUseTightName(familyUnits, givenUnits, totalUnits, compact) {
    if (!givenUnits || compact) return false;
    if (totalUnits >= 7) return true;
    return totalUnits === 5
      && ((familyUnits === 3 && givenUnits === 2) || (familyUnits === 2 && givenUnits === 3));
  }

  function createNameBlock(kind, text, compact) {
    const units = textUnits(text, compact);
    const block = document.createElement("span");
    block.className = `${kind} name-chars ${units.length ? `n${Math.min(units.length, 8)}` : "empty"}`;
    block.style.setProperty("--char-count", String(Math.max(units.length, 1)));
    if (compact) {
      const scale = units.length >= 9 ? 0.89 : 0.92;
      block.style.setProperty("--compact-scale", String(scale));
    }
    units.forEach((unit) => {
      const span = document.createElement("span");
      span.textContent = unit;
      if (compact && /^[ァ-ヶー]+$/.test(unit)) {
        span.classList.add("condensed");
      }
      if (compact && fullSmallKana.has(unit)) {
        span.classList.add("small-kana");
      }
      block.appendChild(span);
    });
    return block;
  }

  function createPlayerName(player) {
    const compact = shouldUseCompactName(player);
    const familyUnits = textUnits(player.family, compact);
    const givenUnits = textUnits(player.given, compact);
    const totalUnits = familyUnits.length + givenUnits.length;
    const name = document.createElement("div");
    name.className = "player-name";
    if (!player.given) name.classList.add("full-name");
    const longName = !compact && (familyUnits.length > 3 || givenUnits.length > 3);
    if (longName) name.classList.add("long-name");
    if (compact) name.classList.add("compact-name");
    if (shouldUseTightName(familyUnits.length, givenUnits.length, totalUnits, compact)) name.classList.add("tight-name");
    name.dataset.compact = compact ? "1" : "0";
    name.dataset.familyUnits = String(familyUnits.length);
    name.dataset.givenUnits = String(givenUnits.length);
    name.dataset.familyVisual = String(compact ? compactUnitLength(familyUnits) : familyUnits.length);
    name.dataset.givenVisual = String(compact ? compactUnitLength(givenUnits) : givenUnits.length);
    name.dataset.totalUnits = String(totalUnits);
    const initialWidths = balanceNameWidths(
      nameBlockWidth(familyUnits.length, totalUnits, longName, compact, compactUnitLength(familyUnits)),
      nameBlockWidth(givenUnits.length, totalUnits, longName, compact, compactUnitLength(givenUnits)),
      familyUnits.length,
      givenUnits.length,
      totalUnits,
      compact,
      longName
    );
    name.style.setProperty("--family-width", `${initialWidths.familyWidth}px`);
    name.style.setProperty("--given-width", `${initialWidths.givenWidth}px`);
    name.style.setProperty("--name-gap", `${compact ? (totalUnits >= 6 ? 14 : 24) : (totalUnits === 5 ? 18 : (totalUnits >= 8 ? 20 : 28))}px`);
    name.append(createNameBlock("family-name", player.family, compact));
    name.append(createNameBlock("given-name", player.given, compact));
    if (player.yellow) {
      const card = document.createElement("span");
      card.className = "yellow-card";
      card.setAttribute("aria-label", "イエローカード");
      name.appendChild(card);
    }
    return name;
  }

  function renderLineup(container, players, side) {
    if (!container) return;
    container.textContent = "";
    let lastPos = "";
    players.forEach((player) => {
      const row = document.createElement("div");
      row.className = "player-row";

      const pos = document.createElement("div");
      pos.className = "pos";
      const currentPos = (player.pos || "").trim();
      pos.textContent = currentPos === lastPos ? "" : currentPos;
      lastPos = currentPos;

      const num = document.createElement("div");
      num.className = `num ${side}-num`;
      num.textContent = player.no;

      row.append(pos, num, createPlayerName(player));
      container.appendChild(row);
    });
  }

  function renderFields(state) {
    document.querySelectorAll("[data-field]").forEach((node) => {
      const value = String(getPath(state, node.dataset.field) ?? "");
      node.textContent = "";
      if (
        node.classList.contains("club-name")
        || node.classList.contains("result-club-bar")
        || node.classList.contains("top-club-ja")
        || node.matches(".top-club-name strong")
      ) {
        const label = document.createElement("span");
        label.className = "fit-label-text";
        label.textContent = value;
        node.appendChild(label);
        return;
      }
      value.split("\n").forEach((line, index) => {
        if (index) node.appendChild(document.createElement("br"));
        node.appendChild(document.createTextNode(line));
      });
    });
  }

  function fitSingleLineLabel(node, options = {}) {
    if (!node || !node.textContent.trim() || !node.clientWidth) return;
    const label = node.querySelector(".fit-label-text") || node;
    const maxFont = Number(options.maxFont) || parseFloat(getComputedStyle(node).fontSize) || 56;
    const baseSpacingEm = Number(options.baseSpacingEm) || 0;
    const minScale = Number(options.minScale) || 0.74;
    const maxWidth = Math.max(40, node.clientWidth - (Number(options.padding) || 42));
    const measureWidth = () => {
      const style = getComputedStyle(node);
      const canvas = fitSingleLineLabel.canvas || (fitSingleLineLabel.canvas = document.createElement("canvas"));
      const context = canvas.getContext("2d");
      context.font = `${style.fontStyle || "normal"} ${style.fontWeight || "900"} ${style.fontSize || `${maxFont}px`} ${style.fontFamily || "sans-serif"}`;
      const text = node.textContent.trim();
      const charCount = Array.from(text.replace(/\s+/g, "")).length;
      const spacingPx = parseFloat(node.style.letterSpacing || style.letterSpacing) || 0;
      return context.measureText(text).width + Math.max(0, charCount - 1) * spacingPx;
    };
    const currentWidth = () => Math.max(label.scrollWidth || 0, measureWidth());

    node.style.fontSize = "";
    node.style.setProperty("--fit-scale", "1");

    const units = Array.from(node.textContent.trim().replace(/\s+/g, ""));
    node.style.letterSpacing = "0px";
    node.style.textIndent = "0px";
    node.style.fontSize = `${maxFont}px`;

    let spacing = units.length > 1 ? maxFont * baseSpacingEm : 0;
    if (options.fillShort && units.length > 1 && units.length <= 6) {
      const naturalWidth = currentWidth();
      const fillSpacing = (maxWidth - naturalWidth) / (units.length - 1);
      const maxSpacing = maxFont * (Number(options.maxSpacingEm) || 0.72);
      spacing = Math.max(spacing, Math.min(maxSpacing, fillSpacing));
    }
    node.style.letterSpacing = `${spacing}px`;
    node.style.textIndent = `${spacing}px`;

    while (spacing > 0 && currentWidth() > maxWidth) {
      spacing = Math.max(0, spacing - 1);
      node.style.letterSpacing = `${spacing}px`;
      node.style.textIndent = `${spacing}px`;
    }
    let finalWidth = currentWidth();
    if (finalWidth > maxWidth && options.shrinkFont) {
      const minFont = Number(options.minFont) || maxFont * minScale;
      const nextFont = Math.max(minFont, Math.floor(maxFont * (maxWidth / finalWidth)));
      node.style.fontSize = `${nextFont}px`;
      node.style.setProperty("--fit-scale", "1");
      finalWidth = currentWidth();
    }
    if (finalWidth > maxWidth) {
      node.style.setProperty("--fit-scale", String(Math.max(minScale, maxWidth / finalWidth)));
    }
  }

  function fitClubLabels() {
    document.querySelectorAll(".club-name, .result-club-bar").forEach((node) => {
      const isAway = node.classList.contains("away-club") || node.classList.contains("result-away-club");
      fitSingleLineLabel(node, {
        maxFont: 56,
        padding: 42,
        baseSpacingEm: isAway ? 0.28 : 0.045,
        fillShort: isAway,
        maxSpacingEm: 0.72,
        minScale: 0.78
      });
    });
    document.querySelectorAll(".top-club-ja").forEach((node) => {
      fitSingleLineLabel(node, { maxFont: 44, padding: 8, baseSpacingEm: 0.012, minScale: 0.72 });
    });
    document.querySelectorAll(".top-club-name strong").forEach((node) => {
      fitSingleLineLabel(node, { maxFont: 74, padding: 0, baseSpacingEm: 0.014, minScale: 0.48, shrinkFont: true, minFont: 42 });
    });
    document.querySelectorAll(".member-club-name").forEach((node) => {
      const isAway = node.closest(".member-side-away");
      fitSingleLineLabel(node, {
        maxFont: 74,
        padding: 42,
        baseSpacingEm: isAway ? 0.18 : 0.045,
        fillShort: Boolean(isAway),
        maxSpacingEm: 0.5,
        minScale: 0.7
      });
    });
  }

  function scheduleClubLabelFit() {
    fitClubLabels();
    const raf = window.requestAnimationFrame || (typeof requestAnimationFrame === "function" ? requestAnimationFrame : null);
    if (raf) raf(fitClubLabels);
    if (document.fonts && document.fonts.ready) {
      document.fonts.ready.then(fitClubLabels).catch(() => {});
    }
  }

  function readNumber(value, fallback = 0) {
    const number = parseFloat(value);
    return Number.isFinite(number) ? number : fallback;
  }

  function fitNameUnits(block) {
    if (!block || !block.classList.contains("name-chars")) return;
    const spans = Array.from(block.querySelectorAll("span"));
    if (!spans.length || !block.clientWidth) return;
    const slot = block.clientWidth / Math.max(1, spans.length);
    const compactBlock = Boolean(block.closest(".compact-name"));
    spans.forEach((span) => {
      span.style.transform = "";
      if (!compactBlock) return;
      const naturalWidth = Math.max(1, span.scrollWidth || span.getBoundingClientRect().width);
      const blockScale = readNumber(getComputedStyle(block).getPropertyValue("--compact-scale"), 0.9);
      const fitScale = Math.min(blockScale, Math.max(0.72, (slot * 0.94) / naturalWidth));
      span.style.transform = `scaleX(${fitScale})`;
    });
  }

  function fitPlayerName(name) {
    if (!name || !name.classList || !name.classList.contains("player-name") || !name.clientWidth) return;
    const compact = name.dataset.compact === "1";
    const familyUnits = readNumber(name.dataset.familyUnits, 0);
    const givenUnits = readNumber(name.dataset.givenUnits, 0);
    const totalUnits = readNumber(name.dataset.totalUnits, familyUnits + givenUnits);
    const familyVisual = readNumber(name.dataset.familyVisual, familyUnits);
    const givenVisual = readNumber(name.dataset.givenVisual, givenUnits);
    const hasGiven = givenUnits > 0 && !name.classList.contains("full-name");
    const longName = name.classList.contains("long-name");
    const tightName = name.classList.contains("tight-name");
    const style = getComputedStyle(name);
    const available = Math.max(
      72,
      name.clientWidth - readNumber(style.paddingLeft, 0) - readNumber(style.paddingRight, 0)
    );

    let familyWidth = nameBlockWidth(familyUnits, totalUnits, longName, compact, familyVisual);
    let givenWidth = nameBlockWidth(givenUnits, totalUnits, longName, compact, givenVisual);
    let gap = compact
      ? (totalUnits >= 6 ? 14 : 24)
      : (tightName ? (totalUnits === 5 ? 18 : (totalUnits >= 8 ? 18 : 24)) : (totalUnits >= 8 ? 20 : 28));

    if (compact) {
      familyWidth = familyUnits ? Math.max(68, Math.min(220, familyVisual * 42 + 12)) : 0;
      givenWidth = givenUnits ? Math.max(68, Math.min(235, givenVisual * 42 + 12)) : 0;
    }
    ({ familyWidth, givenWidth } = balanceNameWidths(
      familyWidth,
      givenWidth,
      familyUnits,
      givenUnits,
      totalUnits,
      compact,
      longName
    ));

    if (!hasGiven) {
      familyWidth = available;
      givenWidth = 0;
      gap = 0;
    } else {
      const effectiveGap = (compact || tightName) ? gap : 0;
      const preferred = familyWidth + givenWidth + effectiveGap;
      if (preferred > available) {
        const minGap = compact ? 8 : 12;
        if (compact || tightName) {
          gap = Math.max(minGap, Math.min(gap, available * (compact ? 0.04 : 0.07)));
        } else {
          gap = 0;
        }
        const blocksAvailable = Math.max(90, available - ((compact || tightName) ? gap : 0));
        const ratio = Math.min(1, blocksAvailable / Math.max(1, familyWidth + givenWidth));
        familyWidth = Math.max(compact ? 54 : 44, familyWidth * ratio);
        givenWidth = Math.max(compact ? 54 : 44, givenWidth * ratio);
        const overflow = familyWidth + givenWidth + ((compact || tightName) ? gap : 0) - available;
        if (overflow > 0) {
          const secondRatio = (available - ((compact || tightName) ? gap : 0)) / Math.max(1, familyWidth + givenWidth);
          familyWidth *= secondRatio;
          givenWidth *= secondRatio;
        }
      }
    }

    name.style.setProperty("--family-width", `${Math.floor(familyWidth)}px`);
    name.style.setProperty("--given-width", `${Math.floor(givenWidth)}px`);
    name.style.setProperty("--name-gap", `${Math.floor(gap)}px`);

    const compactScale = compact
      ? (totalUnits >= 11 ? 0.86 : (totalUnits >= 9 ? 0.89 : 0.92))
      : 1;
    name.querySelectorAll(".name-chars").forEach((block) => {
      block.style.setProperty("--compact-scale", String(compactScale));
      fitNameUnits(block);
    });
  }

  function fitPlayerNames() {
    document.querySelectorAll(".player-name").forEach(fitPlayerName);
  }

  function schedulePlayerNameFit() {
    fitPlayerNames();
    const raf = window.requestAnimationFrame || (typeof requestAnimationFrame === "function" ? requestAnimationFrame : null);
    if (raf) raf(fitPlayerNames);
    if (document.fonts && document.fonts.ready) {
      document.fonts.ready.then(fitPlayerNames).catch(() => {});
    }
  }

  function colorMix(color, percent) {
    const hex = color.replace("#", "");
    const full = hex.length === 3 ? hex.split("").map((c) => c + c).join("") : hex.padEnd(6, "0").slice(0, 6);
    const num = parseInt(full, 16);
    const r = Math.min(255, Math.max(0, ((num >> 16) & 255) + percent));
    const g = Math.min(255, Math.max(0, ((num >> 8) & 255) + percent));
    const b = Math.min(255, Math.max(0, (num & 255) + percent));
    return `rgb(${r}, ${g}, ${b})`;
  }

  function applyColors(state) {
    const root = document.documentElement;
    root.style.setProperty("--home-color", state.colors.home);
    root.style.setProperty("--home-color-light", colorMix(state.colors.home, 34));
    root.style.setProperty("--home-color-dark", colorMix(state.colors.home, -42));
    root.style.setProperty("--away-color", state.colors.away);
    root.style.setProperty("--away-color-light", colorMix(state.colors.away, 34));
    root.style.setProperty("--away-color-dark", colorMix(state.colors.away, -48));
    root.style.setProperty("--center-color", state.colors.center);
    root.style.setProperty("--center-color-light", colorMix(state.colors.center, 34));
    root.style.setProperty("--center-color-dark", colorMix(state.colors.center, -58));
    root.style.setProperty("--home-club-text", state.textColors.homeClub);
    root.style.setProperty("--away-club-text", state.textColors.awayClub);
    root.style.setProperty("--home-number-text", state.textColors.homeNumber);
    root.style.setProperty("--away-number-text", state.textColors.awayNumber);
  }

  function normalizeLeagueLogoSrc(value) {
    const text = String(value || "");
    if (LEAGUE_LOGO_OPTIONS.includes(text)) return text;
    if (/^\.\.\/data\/assets\/icons\/[^"'<>]+\.(png|webp|jpg|jpeg|svg)(\?[^"'<>]*)?$/i.test(text)) return text;
    if (/icons\/j1\.png/i.test(text)) return LEAGUE_LOGO_ASSETS.j1;
    if (/icons\/j2\.png/i.test(text)) return LEAGUE_LOGO_ASSETS.j2;
    if (/icons\/100l\.png/i.test(text)) return LEAGUE_LOGO_ASSETS.hundred;
    return DEFAULT_LEAGUE_ASSET;
  }

  function syncLeagueLogoSelect(state) {
    const select = document.getElementById("leagueLogoSelect");
    if (!select) return;
    select.value = normalizeLeagueLogoSrc(state.images && state.images.league);
  }

  function renderImages(state) {
    const leagueImage = document.getElementById("leagueImage");
    if (leagueImage) {
      leagueImage.src = normalizeLeagueLogoSrc(state.images.league);
    }

    const resultLeagueImage = document.getElementById("resultLeagueImage");
    if (resultLeagueImage) {
      resultLeagueImage.src = normalizeLeagueLogoSrc(state.images.league);
    }

    const topLeagueImage = document.getElementById("topLeagueImage");
    if (topLeagueImage) {
      topLeagueImage.src = normalizeLeagueLogoSrc(state.images.league);
    }

    const image = document.getElementById("customLogo");
    const fallback = document.getElementById("defaultLogo");
    if (!image || !fallback) return;
    if (state.images.bottom) {
      image.src = state.images.bottom;
      image.style.display = "block";
      fallback.style.display = "none";
    } else {
      image.removeAttribute("src");
      image.style.display = "none";
      fallback.style.display = "block";
    }
  }

  function setEmblemImage(image, clubName) {
    if (!image) return;
    const url = getClubEmblemUrl(clubName);
    if (url) {
      image.src = url;
      image.style.visibility = "visible";
    } else {
      image.removeAttribute("src");
      image.style.visibility = "hidden";
    }
  }

  function renderClubEmblems(state) {
    setEmblemImage(document.getElementById("resultHomeEmblem"), state.home.club);
    setEmblemImage(document.getElementById("resultAwayEmblem"), state.away.club);
    setEmblemImage(document.getElementById("attendanceHomeEmblem"), state.home.club);
    setEmblemImage(document.getElementById("attendanceAwayEmblem"), state.away.club);
    setEmblemImage(document.getElementById("topHomeEmblem"), state.home.club);
    setEmblemImage(document.getElementById("topAwayEmblem"), state.away.club);
  }

  function scorerMinuteLabel(value) {
    const clean = String(value || "").trim().replace(/^['’]/, "").replace(/['’]$/, "");
    return clean ? `'${clean}` : "";
  }

  function renderScorers(container, scorers) {
    if (!container) return;
    container.textContent = "";
    (scorers || []).filter((scorer) => scorer && (scorer.minute || scorer.family || scorer.given || scorer.name)).forEach((scorer) => {
      const normalized = normalizeScorer(scorer);
      const row = document.createElement("div");
      row.className = "result-scorer";
      const hasLongMinute = String(normalized.minute || "").includes("+");

      const minute = document.createElement("span");
      minute.className = "result-scorer-minute";
      if (hasLongMinute) minute.classList.add("long-minute");
      const minuteText = document.createElement("span");
      minuteText.className = "result-scorer-minute-text";
      minuteText.textContent = scorerMinuteLabel(normalized.minute);
      minute.appendChild(minuteText);

      const name = createPlayerName(normalized);
      name.classList.add("result-scorer-name");

      row.append(minute, name);
      container.appendChild(row);
    });
  }

  function renderResult(state) {
    renderScorers(document.getElementById("resultHomeScorers"), state.result.homeScorers);
    renderScorers(document.getElementById("resultAwayScorers"), state.result.awayScorers);
  }

  function renderMemberRows(container, players, side, count) {
    if (!container) return;
    container.textContent = "";
    const list = normalizePlayerList(players, [], count);
    let lastPos = "";
    list.forEach((player) => {
      const row = document.createElement("div");
      row.className = "member-row";

      const pos = document.createElement("div");
      pos.className = "pos member-pos";
      const currentPos = (player.pos || "").trim();
      pos.textContent = currentPos === lastPos ? "" : currentPos;
      lastPos = currentPos;

      const num = document.createElement("div");
      num.className = `num member-num ${side}-num`;
      num.textContent = player.no || "";

      const name = createPlayerName({ ...player, yellow: false });
      name.classList.add("member-player-name");

      const filler = document.createElement("div");
      filler.className = "member-filler";

      row.append(pos, num, name, filler);
      container.appendChild(row);
    });
  }

  function setFitText(node, value) {
    if (!node) return;
    node.textContent = "";
    const label = document.createElement("span");
    label.className = "fit-label-text";
    label.textContent = value || "";
    node.appendChild(label);
  }

  function renderAnnouncementBoards(state) {
    document.querySelectorAll("[data-member-screen]").forEach((board) => {
      const screen = board.dataset.memberScreen;
      const isReserve = screen === "reserve";
      const side = state.announcements && state.announcements[isReserve ? "reserveSide" : "startingSide"] === "home" ? "home" : "away";
      const team = state[side] || state.away;
      board.classList.toggle("member-side-home", side === "home");
      board.classList.toggle("member-side-away", side === "away");
      setFitText(board.querySelector(".member-club-name"), team.club || "");
      const list = isReserve ? team.reserves : (team.startingPlayers || team.players);
      renderMemberRows(board.querySelector(".member-list"), list, side, isReserve ? MAX_RESERVES : 11);
    });
  }

  function renderRefereeRows(state) {
    const list = document.querySelector(".referees-list");
    if (!list) return;
    const activeCount = Math.max(1, (state.referees || []).filter((referee) => referee && (referee.role || referee.name)).length);
    list.dataset.refereeCount = String(Math.min(MAX_REFEREES, activeCount));
    list.querySelectorAll(".referee-row").forEach((row, index) => {
      const referee = state.referees[index] || {};
      row.hidden = !(referee.role || referee.name);
    });
  }

  function renderDisplay(state) {
    applyColors(state);
    document.querySelectorAll(".canvas, .vision-board").forEach((node) => {
      node.classList.toggle("is-kickoff", state.match && state.match.phase === "kickoff");
      node.classList.toggle("is-fulltime", !state.match || state.match.phase !== "kickoff");
    });
    renderFields(state);
    renderRefereeRows(state);
    renderLineup(document.getElementById("homeLineup"), state.home.players, "home");
    renderLineup(document.getElementById("awayLineup"), state.away.players, "away");
    renderImages(state);
    renderResult(state);
    renderAnnouncementBoards(state);
    renderClubEmblems(state);
    scheduleClubLabelFit();
    schedulePlayerNameFit();
  }

  function createPlayerEditor(container, side, state, listKey = "players", options = {}) {
    if (!container) return;
    const includeYellow = options.includeYellow !== false;
    const count = listKey === "reserves" ? MAX_RESERVES : 11;
    const players = normalizePlayerList(state[side] && state[side][listKey], [], count);
    container.textContent = "";
    const header = document.createElement("div");
    header.className = `player-edit-row player-edit-head${includeYellow ? "" : " no-yellow"}`;
    ["POS", "No.", "姓", "名", "半角", ...(includeYellow ? ["YC"] : [])].forEach((label) => {
      const span = document.createElement("span");
      span.textContent = label;
      header.appendChild(span);
    });
    container.appendChild(header);

    players.forEach((player, index) => {
      const row = document.createElement("div");
      row.className = `player-edit-row${includeYellow ? "" : " no-yellow"}`;
      [
        ["pos", "GK"],
        ["no", "64"],
        ["family", "藤原"],
        ["given", "奏哉"]
      ].forEach(([key, placeholder]) => {
        const input = document.createElement("input");
        input.name = `${side}.${listKey}.${index}.${key}`;
        input.value = player[key];
        input.placeholder = placeholder;
        row.appendChild(input);
      });
      const toggle = document.createElement("button");
      toggle.type = "button";
      toggle.className = `half-toggle${player.half ? " active" : ""}`;
      toggle.dataset.halfToggle = "true";
      toggle.dataset.side = side;
      toggle.dataset.list = listKey;
      toggle.dataset.index = String(index);
      toggle.textContent = player.half ? "半角ON" : "半角";
      toggle.title = "カタカナの半角表示を切り替えます";
      row.appendChild(toggle);
      if (includeYellow) {
        const yellowToggle = document.createElement("button");
        yellowToggle.type = "button";
        yellowToggle.className = `yellow-toggle${player.yellow ? " active" : ""}`;
        yellowToggle.dataset.yellowToggle = "true";
        yellowToggle.dataset.side = side;
        yellowToggle.dataset.list = listKey;
        yellowToggle.dataset.index = String(index);
        yellowToggle.textContent = player.yellow ? "警告" : "なし";
        yellowToggle.title = "イエローカード表示を切り替えます";
        row.appendChild(yellowToggle);
      }
      container.appendChild(row);
    });
  }

  function createScorerEditor(container, side, state) {
    if (!container) return;
    container.textContent = "";
    const listName = side === "home" ? "homeScorers" : "awayScorers";
    const header = document.createElement("div");
    header.className = "scorer-edit-row scorer-edit-head";
    ["時間", "姓", "名", "半角"].forEach((label) => {
      const span = document.createElement("span");
      span.textContent = label;
      header.appendChild(span);
    });
    container.appendChild(header);

    state.result[listName].forEach((scorer, index) => {
      const normalized = normalizeScorer(scorer);
      const row = document.createElement("div");
      row.className = "scorer-edit-row";
      [
        ["minute", side === "home" && index === 0 ? "47" : ""],
        ["family", side === "home" && index === 0 ? "シマブク" : ""],
        ["given", side === "home" && index === 0 ? "カズヨシ" : ""]
      ].forEach(([key, placeholder]) => {
        const input = document.createElement("input");
        input.name = `result.${listName}.${index}.${key}`;
        input.value = normalized[key];
        input.placeholder = placeholder;
        row.appendChild(input);
      });
      const toggle = document.createElement("button");
      toggle.type = "button";
      toggle.className = `half-toggle${normalized.half ? " active" : ""}`;
      toggle.dataset.scorerHalfToggle = "true";
      toggle.dataset.scorerSide = side;
      toggle.dataset.index = String(index);
      toggle.textContent = normalized.half ? "半角ON" : "半角";
      toggle.title = "カタカナの半角表示を切り替えます";
      row.appendChild(toggle);
      container.appendChild(row);
    });
  }

  function fillForm(form, state) {
    form.querySelectorAll("[name]").forEach((field) => {
      if (field.type === "file") return;
      field.value = getPath(state, field.name) ?? "";
    });
    syncClubSelectors(state);
    syncLeagueLogoSelect(state);
  }

  function readForm(form, state) {
    const next = normalizeState(state);
    form.querySelectorAll("[name]").forEach((field) => {
      if (field.type === "file") return;
      setPath(next, field.name, field.value);
    });
    return next;
  }

  function readImageFile(input, callback) {
    const file = input.files && input.files[0];
    if (!file) return;
    const reader = new FileReader();
    reader.addEventListener("load", () => callback(String(reader.result || "")));
    reader.readAsDataURL(file);
  }

  function normalizeOfficialText(value) {
    return String(value || "")
      .replace(/\r/g, "")
      .replace(/\u3000/g, " ")
      .normalize("NFKC");
  }

  function normalizeOfficialUrl(url) {
    const value = String(url || "").trim();
    if (!/^https?:\/\/data\.j-league\.or\.jp\/SFMS02\//i.test(value)) {
      throw new Error("J.LEAGUE Data Site の公式記録URLを入力してください。");
    }
    return value.replace(/^https:\/\//i, "http://");
  }

